using System;

[AttributeUsage(AttributeTargets.Method)]
public class RunOnStartupAttribute : Attribute { }

class Program
{
    [RunOnStartup]
    static void Initialize() => Console.WriteLine("Initializing...");

    [RunOnStartup]
    static void LoadConfig() => Console.WriteLine("Loading config...");

    static void NotRun() => Console.WriteLine("Not run");

    static void Main()
    {
        var methods = typeof(Program).GetMethods();
        foreach (var method in methods)
        {
            if (method.GetCustomAttributes(typeof(RunOnStartupAttribute), false).Length > 0)
                method.Invoke(null, null);
        }
    }
}
